class CombinationIterator:

    def __init__(self, characters: str, combinationLength: int):
        self.chars = characters
        self.length = combinationLength
        self.index = 0
        self.combinations = self.generate_combinations()

    def generate_combinations(self):
        combinations = []
        for i in range(len(self.chars)):
            if i > 0:
                combinations.extend([c + self.chars[i] for c in self.combinations[-1]])
            else:
                combinations.append(self.chars[i])
        return combinations

    def next(self) -> str:
        if self.index < len(self.combinations):
            result = self.combinations[self.index]
            self.index += 1
            return result
        return ""

    def hasNext(self) -> bool:
        return self.index < len(self.combinations)
